        return ""

    try:
        # Parse the expression into an AST
        tree = ast.parse(expr, mode='eval')

        # Evaluate using safe AST evaluation
        result = _safe_eval(tree.body)

        # Check if result is a number
        if isinstance(result, (int, float)):
