def sanitize_email(email: str) -> bool:
    if not isinstance(email, str):
        return False

    try:
        # Decode URL-encoded email to prevent bypass through encoding
        decoded_email = unquote(email)

        # Additional security: prevent multiple rounds of decoding
        # by checking if further decoding would change the string
        prev_decoded = decoded_email
        while True:
            next_decoded = unquote(prev_decoded)
            if next_decoded == prev_decoded:
                break
            prev_decoded = next_decoded

        final_email = prev_decoded

        # Validate against the regex pattern
        return bool(valid_email_pattern.match(final_email))

    except Exception:
        return False

