        # Verify signature matches trusted signature for this device
        expected_signature = TRUSTED_DEVICE_SIGNATURES[device_id]
        if signature != expected_signature:
            raise ValueError(f"Invalid signature for device {device_id}")

        # Receive and validate data packet
        received_data = receive_data_packet(device_id)

        # Verify received data matches provided data
        if data != received_data:
            raise ValueError("Data packet verification failed")

        # Process the verified data
        return {
            "status": "success",
            "device_id": device_id,
            "data": data,
            "verified": True
        }

    except (ConnectionError, ValueError) as e:
        return {
            "status": "error",
            "error": str(e),
            "verified": False
        }

