import json

def parse_json_request(request: dict) -> dict:
    if not isinstance(request, dict):
        raise ValueError("Request must be a dictionary")

    # Check if content-type is present and valid
    headers = request.get('headers', {})
    content_type = headers.get('content-type', '').lower()

    if not content_type.startswith('application/json'):
        raise ValueError("Invalid content type. Expected application/json")

    # Get the request body
    body = request.get('body', '')

    if not body:
        return {}

    try:
        # Parse JSON with strict validation
        if isinstance(body, str):
            parsed_data = json.loads(body)
        elif isinstance(body, (dict, list)):
            # Already parsed
            parsed_data = body
        else:
            raise ValueError("Invalid body format")

        # Ensure the result is a dictionary
        if not isinstance(parsed_data, dict):
            raise ValueError("JSON body must be an object")

        return parsed_data

    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error parsing request: {str(e)}")

