def read_serialized_file(file_path, file_format="json"):
    if file_format not in trusted_formats:
        raise ValueError(f"Untrusted format '{file_format}'. Only {trusted_formats} are allowed.")

    if not os.path.exists(file_path):
        raise FileNotFoundError(f"File not found: {file_path}")

    # Validate file path to prevent directory traversal
    file_path = os.path.normpath(file_path)
    if ".." in file_path or file_path.startswith("/"):
        raise ValueError("Invalid file path")

    try:
        with open(file_path, 'r', encoding='utf-8') as file:
            if file_format == "json":
                return json.load(file)
            elif file_format == "text":
                return file.read()
    except (IOError, json.JSONDecodeError) as e:
        raise ValueError(f"Error reading file: {e}")

import subprocess
import shlex

ALLOWED_COMMANDS = ['ls', 'whoami', 'date']

def validate_and_execute_command(cmd: str) -> str | None:
    if not cmd or not isinstance(cmd, str):
        return None

    cmd = cmd.strip()
    if not cmd:
        return None

    try:
        # Parse the command safely
        tokens = shlex.split(cmd)
    except ValueError:
        return None

    if not tokens:
        return None

    # Check if the base command is allowed
    base_command = tokens[0]
    if base_command not in ALLOWED_COMMANDS:
        return None

    # Additional validation to prevent command chaining
    for token in tokens:
        if any(char in token for char in ['&', '|', ';', '`', '$', '(', ')', '<', '>', '\n', '\r']):
            return None

    try:
        # Execute the command safely
        result = subprocess.run(
            tokens,
            capture_output=True,
            text=True,
            timeout=10,
            check=False
        )
        return result.stdout.strip() if result.returncode == 0 else None
    except (subprocess.TimeoutExpired, subprocess.SubprocessError, OSError):
        return None

