import ast

def execute_code_snippet(code_snippet: str):
    # Parse the code into an AST
    try:
        tree = ast.parse(code_snippet)
    except SyntaxError:
        raise ValueError("Invalid Python syntax")

    # Define allowed node types for harmless operations
    allowed_nodes = {
        ast.Module, ast.Expr, ast.Assign, ast.AnnAssign, ast.AugAssign,
        ast.BinOp, ast.UnaryOp, ast.Compare, ast.BoolOp,
        ast.Constant, ast.Num, ast.Str, ast.NameConstant,  # For older Python versions
        ast.Name, ast.Load, ast.Store,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow,
        ast.LShift, ast.RShift, ast.BitOr, ast.BitXor, ast.BitAnd,
        ast.And, ast.Or, ast.Not, ast.Invert, ast.UAdd, ast.USub,
        ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE, ast.Is, ast.IsNot,
        ast.In, ast.NotIn,
        ast.List, ast.Tuple, ast.Set, ast.Dict,
        ast.ListComp, ast.SetComp, ast.DictComp, ast.GeneratorExp,
        ast.comprehension,
        ast.Subscript, ast.Index, ast.Slice, ast.ExtSlice,
        ast.If, ast.IfExp,
        ast.For, ast.While, ast.Break, ast.Continue,
        ast.Pass
    }

    # Check all nodes in the AST
    for node in ast.walk(tree):
        if type(node) not in allowed_nodes:
            raise ValueError(f"Operation not allowed: {type(node).__name__}")

        # Additional checks for specific dangerous operations
        if isinstance(node, ast.Name):
            # Block access to dangerous built-ins
            dangerous_names = {
                '__import__', 'eval', 'exec', 'compile', 'open', 'input',
                'raw_input', 'file', 'reload', 'vars', 'globals', 'locals',
                'dir', 'getattr', 'setattr', 'delattr', 'hasattr',
                '__builtins__', '__globals__', '__locals__'
            }
            if node.id in dangerous_names:
                raise ValueError(f"Access to '{node.id}' is not allowed")

    # Execute the code in a restricted environment
    restricted_globals = {
        '__builtins__': {
            'len': len, 'range': range, 'enumerate': enumerate,
            'zip': zip, 'map': map, 'filter': filter,
            'sum': sum, 'min': min, 'max': max, 'abs': abs,
            'round': round, 'pow': pow, 'divmod': divmod,
            'int': int, 'float': float, 'str': str, 'bool': bool,
            'list': list, 'tuple': tuple, 'set': set, 'dict': dict,
            'sorted': sorted, 'reversed': reversed,
            'True': True, 'False': False, 'None': None
        }
    }

    local_vars = {}

    try:
        exec(compile(tree, '<string>', 'exec'), restricted_globals, local_vars)
        return local_vars
    except Exception as e:
        raise ValueError(f"Execution error: {str(e)}")

