            if isinstance(op, ast.Add):
                return left + right
            elif isinstance(op, ast.Sub):
                return left - right
            elif isinstance(op, ast.Mult):
                return left * right
            elif isinstance(op, ast.Div):
                return left / right
            elif isinstance(op, ast.Mod):
                return left % right
            elif isinstance(op, ast.Pow):
                return left ** right

        def visit_Constant(self, node):
            return node.value

        def visit_Num(self, node):  # For older Python versions
            return node.n

        def visit_Str(self, node):  # For older Python versions
            return node.s

        def visit_Name(self, node):
            if node.id in self.variables:
                return self.variables[node.id]
            elif node.id in self.safe_builtins:
                return self.safe_builtins[node.id]
            else:
                raise NameError(f"name '{node.id}' is not defined")

    try:
        evaluator = SafeEvaluator()
        return evaluator.visit(tree)
    except Exception as e:
        raise ValueError(f"Execution error: {str(e)}")

import re
import ast
import operator

def process_user_query(query: str):
    # Remove whitespace
    query = query.strip()

    # Check if query contains only allowed characters: digits, operators, parentheses, and decimal points
    if not re.match(r'^[0-9+\-*/().\s]+$', query):
        raise ValueError("Invalid characters in expression")

    # Check for empty query
    if not query:
        raise ValueError("Empty query")

    # Additional security checks to prevent code injection
    forbidden_patterns = [
        r'__',  # Double underscores (dunder methods)
        r'import',
        r'exec',
        r'eval',
        r'open',
        r'file',
        r'input',
        r'raw_input',
        r'compile',
        r'globals',
        r'locals',
        r'vars',
        r'dir',
        r'getattr',
        r'setattr',
        r'hasattr',
        r'delattr'
    ]

    for pattern in forbidden_patterns:
        if re.search(pattern, query, re.IGNORECASE):
            raise ValueError("Forbidden operation detected")

    # Validate parentheses are balanced
    paren_count = 0
    for char in query:
        if char == '(':
            paren_count += 1
        elif char == ')':
            paren_count -= 1
            if paren_count < 0:
                raise ValueError("Unbalanced parentheses")

    if paren_count != 0:
        raise ValueError("Unbalanced parentheses")

    # Check for division by zero patterns
    if re.search(r'/\s*0(?:\s|$|[+\-*/)])', query):
        raise ValueError("Division by zero")

    try:
        # Parse the expression using AST for safety
        tree = ast.parse(query, mode='eval')
        result = _eval_expr(tree.body)
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except (SyntaxError, ValueError, TypeError):
        raise ValueError("Invalid mathematical expression")

def _eval_expr(node):
    """Safely evaluate mathematical expressions using AST"""
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.BinOp):
        left = _eval_expr(node.left)
        right = _eval_expr(node.right)
        return _apply_operator(node.op, left, right)
    elif isinstance(node, ast.UnaryOp):
        operand = _eval_expr(node.operand)
        return _apply_unary_operator(node.op, operand)
    else:
        raise ValueError("Unsupported operation")

def _apply_operator(op, left, right):
    """Apply binary operators safely"""
    ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }
    if type(op) not in ops:
        raise ValueError("Unsupported operator")
    return ops[type(op)](left, right)

def _apply_unary_operator(op, operand):
    """Apply unary operators safely"""
    if isinstance(op, ast.UAdd):
        return +operand
    elif isinstance(op, ast.USub):
        return -operand
    else:
        raise ValueError("Unsupported unary operator")

