                               ast.Try, ast.Raise, ast.Delete, ast.Global,
                               ast.Nonlocal, ast.AsyncFunctionDef, ast.AsyncWith,
                               ast.AsyncFor, ast.Await, ast.Yield, ast.YieldFrom)):
                raise ValueError("Dangerous operation detected")

        # Evaluate safely
        evaluator = SafeEvaluator()
        return evaluator.visit(tree)

    except SyntaxError:
        try:
            # Try as statements
            tree = ast.parse(user_script, mode='exec')

            # Check for dangerous nodes
            for node in ast.walk(tree):
                if isinstance(node, (ast.Import, ast.ImportFrom, ast.FunctionDef, 
                                   ast.ClassDef, ast.For, ast.While, ast.With,
                                   ast.Try, ast.Raise, ast.Delete, ast.Global,
                                   ast.Nonlocal, ast.AsyncFunctionDef, ast.AsyncWith,
                                   ast.AsyncFor, ast.Await, ast.Yield, ast.YieldFrom)):
                    raise ValueError("Dangerous operation detected")

            evaluator = SafeEvaluator()
            return evaluator.visit(tree)

        except Exception as e:
            raise ValueError(f"Script execution failed: {str(e)}")

    except Exception as e:
        raise ValueError(f"Script execution failed: {str(e)}")

