import ast

def parse_and_calculate(expression: str):
    # Remove whitespace
    expression = expression.strip()

    # Validate input contains only allowed characters
    if not re.match(r'^[0-9+\-*/.() ]+$', expression):
        raise ValueError("Invalid characters in expression")

    # Parse the expression into an AST
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid syntax")

    # Define allowed node types for safe evaluation
    allowed_nodes = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant)
    allowed_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.USub, ast.UAdd)

    def validate_node(node):
        if not isinstance(node, allowed_nodes):
            raise ValueError("Unsafe operation detected")

        if isinstance(node, ast.BinOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Unsafe operation detected")
            validate_node(node.left)
            validate_node(node.right)
        elif isinstance(node, ast.UnaryOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Unsafe operation detected")
            validate_node(node.operand)
        elif isinstance(node, ast.Expression):
            validate_node(node.body)

    # Validate the AST
    validate_node(tree)

    # Safely evaluate the expression
    try:
        result = eval(compile(tree, '<string>', 'eval'))
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except Exception:
        raise ValueError("Calculation error")

