import ast
import operator
import math

def process_user_expression(expr: str) -> str:
    try:
        # Whitelist of safe operations
        safe_operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        # Whitelist of safe functions
        safe_functions = {
            'abs': abs,
            'min': min,
            'max': max,
            'round': round,
            'sum': sum,
            'len': len,
            'int': int,
            'float': float,
            'str': str,
            'sqrt': math.sqrt,
            'sin': math.sin,
            'cos': math.cos,
            'tan': math.tan,
            'log': math.log,
            'exp': math.exp,
            'ceil': math.ceil,
            'floor': math.floor,
        }

        def safe_eval(node):
            if isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Num):  # Python < 3.8 compatibility
                return node.n
            elif isinstance(node, ast.Str):  # Python < 3.8 compatibility
                return node.s
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op = safe_operators.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                op = safe_operators.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(operand)
            elif isinstance(node, ast.Call):
                if isinstance(node.func, ast.Name):
                    func_name = node.func.id
                    if func_name in safe_functions:
                        args = [safe_eval(arg) for arg in node.args]
                        return safe_functions[func_name](*args)
                raise ValueError("Unsupported function")
            elif isinstance(node, ast.List):
                return [safe_eval(item) for item in node.elts]
            elif isinstance(node, ast.Tuple):
                return tuple(safe_eval(item) for item in node.elts)
            elif isinstance(node, ast.Compare):
                left = safe_eval(node.left)
                for op, comparator in zip(node.ops, node.comparators):
                    right = safe_eval(comparator)
                    if isinstance(op, ast.Lt):
                        if not (left < right):
                            return False
                    elif isinstance(op, ast.LtE):
                        if not (left <= right):
                            return False
                    elif isinstance(op, ast.Gt):
                        if not (left > right):
                            return False
                    elif isinstance(op, ast.GtE):
                        if not (left >= right):
                            return False
                    elif isinstance(op, ast.Eq):
                        if not (left == right):
                            return False
                    elif isinstance(op, ast.NotEq):
                        if not (left != right):
                            return False
                    else:
                        raise ValueError("Unsupported comparison")
                    left = right
                return True
            else:
                raise ValueError("Unsupported expression")

        # Parse and validate the expression
        tree = ast.parse(expr.strip(), mode='eval')
        result = safe_eval(tree.body)
        return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, OverflowError) as e:
        return f"Error: {str(e)}"
    except Exception:
        return "Error: Invalid expression"

import re
import ast
import operator

def exec_calculation(calc_string: str) -> str:
    try:
        # Remove whitespace
        calc_string = calc_string.strip()

        # Check if string is empty
        if not calc_string:
            return "Error: Empty expression"

        # Only allow safe characters: digits, operators, parentheses, decimal points
        if not re.match(r'^[0-9+\-*/().\ ]+$', calc_string):
            return "Error: Invalid characters in expression"

        # Parse the expression into an AST
        try:
            node = ast.parse(calc_string, mode='eval')
        except SyntaxError:
            return "Error: Invalid syntax"

        # Define allowed operations
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def eval_node(node):
            if isinstance(node, ast.Expression):
                return eval_node(node.body)
            elif isinstance(node, ast.Num):  # Python < 3.8
                return node.n
            elif isinstance(node, ast.Constant):  # Python >= 3.8
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Invalid constant type")
            elif isinstance(node, ast.BinOp):
                left = eval_node(node.left)
                right = eval_node(node.right)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = eval_node(node.operand)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(operand)
            else:
                raise ValueError("Unsupported node type")

        result = eval_node(node)

        # Check for division by zero or invalid results
        if result == float('inf') or result == float('-inf') or str(result) == 'nan':
            return "Error: Invalid result"

        # Format result
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        else:
            return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except (ValueError, TypeError, OverflowError):
        return "Error: Invalid expression"
    except Exception:
        return "Error: Calculation failed"

