    try:
        # Whitelist of allowed characters and patterns
        import re
        import ast
        import operator

        # Remove whitespace
        query = query.strip()

        if not query:
            return "Error: Empty query"

        # Only allow basic mathematical expressions and safe operations
        allowed_chars = re.compile(r'^[0-9+\-*/().\s]+$')
        if not allowed_chars.match(query):
            return "Error: Invalid characters in query"

        # Parse the expression using AST to ensure it's safe
        try:
            tree = ast.parse(query, mode='eval')
        except SyntaxError:
            return "Error: Invalid syntax"

        # Define allowed operations
        allowed_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def eval_node(node):
            if isinstance(node, ast.Num):  # Numbers
                return node.n
            elif isinstance(node, ast.Constant):  # Python 3.8+
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Only numeric constants allowed")
            elif isinstance(node, ast.BinOp):  # Binary operations
                left = eval_node(node.left)
                right = eval_node(node.right)
                op = allowed_ops.get(type(node.op))
                if op is None:
                    raise ValueError("Operation not allowed")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):  # Unary operations
                operand = eval_node(node.operand)
                op = allowed_ops.get(type(node.op))
                if op is None:
                    raise ValueError("Operation not allowed")
                return op(operand)
            else:
                raise ValueError("Node type not allowed")

        result = eval_node(tree.body)
        return str(result)

    except ZeroDivisionError:
